// Extract users array into individual items for the loop
const response = $input.first().json;
if (!response.ok || !response.users || response.users.length === 0) {
  return [{ json: { _skip: true, reason: 'No active users found', count: 0 } }];
}

console.log(`[ENLAZE Agent] Processing ${response.users.length} users`);

return response.users.map(u => ({ json: u }));

// Skip guard — if no users, stop here
const item = $input.first().json;
if (item._skip) {
  return [{ json: { done: true, reason: item.reason } }];
}
// Otherwise pass through (this node is only reached inside the loop)
return $input.all();

// parse_news — Filtra noticias RSS usando keywords + rss_filter_hints del usuario
const config = $node['Get User Config'].json;
const baseKeywords = [
  'comercio local', 'pyme', 'autónomo', 'subvención', 'digitalización',
  'hostelería', 'comercio minorista', 'iva', 'seguridad social',
  'licencia apertura', 'kit digital', 'empleo', 'inflación',
  'turismo', 'consumo', 'alquiler', 'energía', 'impuesto'
];
const userKeywords = config.keywords || [];
const rssHints = config.rss_filter_hints || [];
const keywords = [...new Set([...baseKeywords, ...userKeywords, ...rssHints])].map(k => k.toLowerCase());

function parseRSS(xml, src) {
  const items = [];
  const rx = /<item[^>]*>([\s\S]*?)<\/item>/gi;
  let m;
  while ((m = rx.exec(xml)) !== null) {
    const b = m[1];
    const title = (b.match(/<title[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/s)||[])[1]||'';
    const link = (b.match(/<link[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/link>/s)||[])[1]||'';
    const desc = (b.match(/<description[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/description>/s)||[])[1]||'';
    const pubDate = (b.match(/<pubDate[^>]*>(.*?)<\/pubDate>/s)||[])[1]||'';
    items.push({ title: title.trim(), link: link.trim(), desc: desc.trim(), pubDate: pubDate.trim(), source: src });
  }
  return items;
}
function strip(s) { return s.replace(/<[^>]*>/g,'').replace(/&[a-z]+;/gi,' ').trim(); }
function score(title, desc) {
  const t = (title+' '+desc).toLowerCase();
  let s = 0;
  for (const kw of keywords) { if (t.includes(kw)) s += 3; }
  return Math.min(s, 10);
}

const all = [];
for (const item of $input.all()) {
  const d = item.json.data || item.json.body || item.json;
  const txt = typeof d === 'string' ? d : JSON.stringify(d);
  let src = 'Desconocido';
  if (txt.includes('elpais.com')) src = 'El País';
  else if (txt.includes('europapress')) src = 'Europa Press';
  else if (txt.includes('cincodias')) src = 'Cinco Días';
  all.push(...parseRSS(txt, src));
}

const news = all.map(i => {
  const rel = score(i.title, i.desc);
  return {
    id: 'news_' + Buffer.from(i.link||i.title).toString('base64').slice(0,12),
    title: strip(i.title), summary: strip(i.desc).slice(0,300),
    source: i.source, url: i.link,
    date: i.pubDate ? new Date(i.pubDate).toISOString().split('T')[0] : new Date().toISOString().split('T')[0],
    category: 'noticias', relevance: rel,
    tags: keywords.filter(kw => (i.title+' '+i.desc).toLowerCase().includes(kw))
  };
}).filter(n => n.relevance >= 3).sort((a,b) => b.relevance - a.relevance).slice(0,15);

return [{ json: { news } }];

// parse_ayudas — Filtra ayudas BOE usando keywords del usuario
const config = $node['Get User Config'].json;
const baseKw = ['pyme','comercio','digitalización','kit digital','autónomo','empleo','formación','subvención','ayuda','bonificación','hostelería','turismo'];
const userKw = (config.keywords || []).map(k=>k.toLowerCase());
const keywords = [...new Set([...baseKw,...userKw])];

function parseRSS(xml) {
  const items = [];
  const rx = /<item[^>]*>([\s\S]*?)<\/item>/gi;
  let m;
  while ((m = rx.exec(xml)) !== null) {
    const b = m[1];
    const title = (b.match(/<title[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/s)||[])[1]||'';
    const link = (b.match(/<link[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/link>/s)||[])[1]||'';
    const desc = (b.match(/<description[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/description>/s)||[])[1]||'';
    items.push({ title: title.trim(), link: link.trim(), desc: desc.trim() });
  }
  return items;
}
function strip(s) { return s.replace(/<[^>]*>/g,'').replace(/&[a-z]+;/gi,' ').trim(); }
function classify(t, d) {
  const x = (t+' '+d).toLowerCase();
  if (x.includes('subvención')||x.includes('subvencion')) return 'subvención';
  if (x.includes('bonificación')||x.includes('bonificacion')) return 'bonificación';
  if (x.includes('formación')||x.includes('formacion')) return 'formación';
  return 'ayuda';
}

let xml = '';
for (const i of $input.all()) {
  const d = i.json.data || i.json.body || i.json;
  xml += typeof d === 'string' ? d : JSON.stringify(d);
}

const raw = parseRSS(xml);
const subsidies = [], regulations = [];

for (const i of raw) {
  const text = (i.title+' '+i.desc).toLowerCase();
  if (!keywords.some(kw => text.includes(kw))) continue;
  const ct = strip(i.title), cd = strip(i.desc);
  if (text.includes('normativa')||text.includes('reglamento')||text.includes('obligación')||text.includes('ley ')) {
    regulations.push({ id:'reg_'+Buffer.from(i.link||i.title).toString('base64').slice(0,12), title:ct, type:'normativa', summary:cd.slice(0,300), url:i.link, impact:text.includes('obligat')||text.includes('sanción')?'high':'medium', action_required:'Revisar requisitos y plazos' });
  } else {
    subsidies.push({ id:'sub_'+Buffer.from(i.link||i.title).toString('base64').slice(0,12), title:ct, type:classify(i.title,i.desc), amount_range:'', deadline:'', target:'Pymes y autónomos', url:i.link, status:'abierta' });
  }
}

return [{ json: { subsidies: subsidies.slice(0,10), regulations: regulations.slice(0,10) } }];

// build_radar — Combina news + ayudas
const items = $input.all();
let news=[], subsidies=[], regulations=[];
for (const i of items) {
  if (i.json.news) news = i.json.news;
  if (i.json.subsidies) subsidies = i.json.subsidies;
  if (i.json.regulations) regulations = i.json.regulations;
}
return [{ json: { radar: { news, regulations, subsidies, competitor_signals: [], local_events: [] } } }];

// Analyze reviews from Google Places (new API)
const config = $node['Get User Config'].json;
const placeData = $input.first().json;
const reviews = placeData.reviews || [];
const currentRating = placeData.rating || 0;
const totalReviews = placeData.userRatingCount || 0;

const themeKw = {
  espera: ['espera','tardaron','lento','rápido','rapidez','demora'],
  trato: ['trato','amable','simpático','maleducado','atención','servicio'],
  precio: ['precio','caro','barato','económico','relación calidad'],
  limpieza: ['limpio','sucio','limpieza','higiene'],
  calidad: ['calidad','bueno','malo','fresco','rico','delicioso','mediocre'],
  ambiente: ['ambiente','acogedor','ruidoso','tranquilo','decoración'],
};

function themes(text) {
  if (!text) return [];
  const l = text.toLowerCase();
  return Object.entries(themeKw).filter(([,kws]) => kws.some(kw => l.includes(kw))).map(([t]) => t);
}

function suggestResponse(r) {
  const name = r.authorAttribution?.displayName || 'cliente';
  if ((r.rating||0) <= 2) return `Estimado/a ${name}, lamentamos que su experiencia no haya sido satisfactoria. Nos encantaría conocer más detalles para mejorar. ¿Podría contactarnos directamente?`;
  if ((r.rating||0) === 3) return `Gracias por su visita, ${name}. Tomamos nota y trabajaremos para mejorar.`;
  return null;
}

let pos=0, neu=0, neg=0;
const urgent = [], allThemes = [];

for (const r of reviews) {
  const rating = r.rating || 3;
  if (rating >= 4) pos++; else if (rating === 3) neu++; else neg++;
  const t = themes(r.text?.text || r.originalText?.text || '');
  allThemes.push(...t);
  if (rating <= 2) {
    urgent.push({
      author: r.authorAttribution?.displayName || 'Anónimo',
      rating, text: (r.text?.text || r.originalText?.text || '').slice(0,500),
      date: r.publishTime || null, themes: t, responded: false,
      suggested_response: suggestResponse(r)
    });
  }
}

const tc = {};
for (const t of allThemes) tc[t] = (tc[t]||0)+1;
const recurring = Object.entries(tc).filter(([,c])=>c>=2).sort((a,b)=>b[1]-a[1]).map(([t])=>t);

return [{ json: { reputation: { reviews: {
  current_rating: currentRating, total_reviews: totalReviews,
  new_reviews_count: reviews.length,
  sentiment_breakdown: { positive: pos, neutral: neu, negative: neg },
  recurring_themes: recurring, urgent: urgent.slice(0,5),
  trend: pos > neg ? 'improving' : neg > pos ? 'declining' : 'stable'
} } } }];

// Generate marketing ideas based on business_type, calendar, and marketing_hints
const config = $node['Get User Config'].json;
const bizType = (config.business_type || 'comercio').toLowerCase();
const bizName = config.business_name || 'Mi Negocio';
const hints = config.marketing_hints || [];

const now = new Date();
const month = now.getMonth() + 1;
const dates30 = [];
for (let i = 0; i < 30; i++) {
  const d = new Date(now.getTime() + i * 86400000);
  dates30.push({ date: d, m: d.getMonth()+1, d: d.getDate(), dow: d.getDay() });
}

const calendar = [
  { m:1,d:6,name:'Reyes',for:['tienda','comercio'] },
  { m:2,d:14,name:'San Valentín',for:['restaurante','bar','estetica','peluqueria','floristeria'] },
  { m:3,d:8,name:'Día de la Mujer',for:['estetica','peluqueria'] },
  { m:3,d:19,name:'Día del Padre',for:['tienda','restaurante','bar','peluqueria'] },
  { m:5,d:1,name:'Día del Trabajador',for:['todos'] },
  { m:5,d:4,name:'Día de la Madre',for:['tienda','restaurante','estetica','peluqueria','floristeria'] },
  { m:6,d:21,name:'Inicio Verano',for:['todos'] },
  { m:9,d:1,name:'Vuelta al cole',for:['tienda','peluqueria'] },
  { m:10,d:31,name:'Halloween',for:['bar','restaurante','tienda'] },
  { m:11,d:25,name:'Black Friday',for:['todos'] },
  { m:12,d:25,name:'Navidad',for:['todos'] },
  { m:12,d:31,name:'Nochevieja',for:['restaurante','bar'] },
];

const upcoming = [], campaigns = [];
const norm = s => s.normalize('NFD').replace(/[\u0300-\u036f]/g,'');
const bt = norm(bizType);

for (const e of calendar) {
  for (const d of dates30) {
    if (d.m === e.m && d.d === e.d) {
      if (e.for.includes('todos') || e.for.some(t => bt.includes(t))) {
        const ds = d.date.toISOString().split('T')[0];
        upcoming.push({ name: e.name, date: ds });
        campaigns.push({ title:`Campaña ${e.name}`, type:'promotion', channel:['whatsapp','instagram'], target_audience:'clientes_recurrentes', suggested_date:ds, message_draft:`¡${e.name} se acerca! En ${bizName} tenemos algo especial. ¡No te lo pierdas!`, reason:`Fecha señalada: ${e.name}` });
      }
    }
  }
}

// Valley day for hospitality
if (['bar','restaurante','cafeteria','cafe'].some(t => bt.includes(t))) {
  const tue = dates30.find(d => d.dow === 2);
  if (tue) {
    campaigns.push({ title:'Promo día valle — Martes', type:'promotion', channel:['whatsapp','instagram'], target_audience:'clientes_recurrentes', suggested_date:tue.date.toISOString().split('T')[0], message_draft:`¡Este martes en ${bizName} oferta especial entre semana!`, reason:'Martes = día valle en hostelería' });
  }
}

// Business-type-specific hint campaign
if (hints.length > 0 && campaigns.length < 3) {
  const hint = hints[Math.floor(Math.random() * hints.length)];
  campaigns.push({ title:`Idea: ${hint}`, type:'content', channel:['instagram'], target_audience:'todos', suggested_date:dates30[3]?.date.toISOString().split('T')[0]||'', message_draft:`¡Novedad en ${bizName}! ${hint.charAt(0).toUpperCase()+hint.slice(1)}. ¡Ven a probarlo!`, reason:`Idea basada en tipo de negocio: ${bizType}` });
}

// Seasonal fallback
if (campaigns.length === 0) {
  let idea = '';
  if (month>=6&&month<=8) idea = 'Campaña de verano';
  else if (month>=11||month<=1) idea = 'Campaña navideña';
  else if (month>=3&&month<=5) idea = 'Campaña de primavera';
  else idea = 'Campaña de otoño';
  campaigns.push({ title:idea, type:'content', channel:['instagram'], target_audience:'todos', suggested_date:dates30[3]?.date.toISOString().split('T')[0]||'', message_draft:`¡Novedades en ${bizName}! Descubre lo que tenemos esta temporada.`, reason:'Campaña estacional' });
}

return [{ json: { campaigns, upcoming_dates: upcoming } }];

// Combine reviews + marketing into reputation
const items = $input.all();
let reputation = { reviews: {} }, campaigns = [];
for (const i of items) {
  if (i.json.reputation) reputation = i.json.reputation;
  if (i.json.campaigns) campaigns = i.json.campaigns;
}
reputation.campaigns = campaigns;
return [{ json: { reputation } }];

// Build final payload for this user
const items = $input.all();
const config = $node['Get User Config'].json;

let radar = { news:[], regulations:[], subsidies:[], competitor_signals:[], local_events:[] };
let reputation = { reviews:{}, campaigns:[] };

for (const i of items) {
  if (i.json.radar) radar = { ...radar, ...i.json.radar };
  if (i.json.reputation) reputation = { ...reputation, ...i.json.reputation };
}

const nc = (radar.news||[]).length;
const sc = (radar.subsidies||[]).length;
const rc = (radar.regulations||[]).length;
const ur = reputation.reviews?.urgent?.length || 0;
const cc = (reputation.campaigns||[]).length;

let headline = `Hoy tienes ${nc} noticias relevantes`;
if (sc > 0) headline += `, ${sc} ayudas disponibles`;
if (ur > 0) headline += `, ${ur} reseñas que requieren atención`;
headline += '.';

const actions = [];
if (ur > 0) actions.push(`Responder a ${ur} reseña(s) negativa(s)`);
if (sc > 0) actions.push(`Revisar ${sc} ayuda(s)/subvención(es)`);
if (rc > 0) actions.push(`Revisar ${rc} cambio(s) normativo(s)`);
if (cc > 0) actions.push(`Considerar ${cc} idea(s) de marketing`);

const score = Math.max(0, Math.min(100, 40 + nc*3 + sc*8 + cc*5 - ur*10 - rc*5));

return [{ json: {
  user_id: config.user_id,
  agent: 'comercio_local',
  version: '2.0',
  business_id: config.business_id || null,
  timestamp: new Date().toISOString(),
  daily_summary: { headline, priority_actions: actions, opportunities_count: sc+cc, risks_count: rc+ur, score },
  radar,
  reputation
} }];

// Log result and continue loop
const result = $input.first().json;
const config = $node['Get User Config'].json;
console.log(`[ENLAZE Agent] Done: ${config.business_name} (${config.user_id}) — success: ${result.success}`);
return [{ json: { user_id: config.user_id, business_name: config.business_name, success: result.success, timestamp: result.timestamp } }];

// Check if google_place_id exists — if not, skip Google Places
const config = $node['Get User Config'].json;
const hasPlace = config.google_place_id && config.google_place_id !== '' && config.google_place_id !== 'demo-place-id';
return [{ json: { ...config, _has_place: hasPlace } }];
